#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    const int result = 10 * 25; // product of first and third elements
    for (int i = 0; i < T; ++i) {
        printf("%d\n", result);
    }
    return 0;
}

